Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class MyTests : IDisposable
{
    private string? _tempFile;

    // 1. Windows-only (MSTest 3.10+)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (MSTest 3.10+)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void GpuRendering_ProducesExpectedOutput()
    {
        // Runs locally only, skipped in CI
    }

    // 3. Flaky external API (MSTest 3.9+)
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var result = await _client.GetForecastAsync(_testContext.CancellationToken);
        Assert.IsNotNull(result);
    }

    // 4. Cleanup temp files even on failure — use [TestCleanup]
    [TestMethod]
    public void Export_WritesToTempFile()
    {
        _tempFile = Path.GetTempFileName();
        File.WriteAllText(_tempFile, "data");

        var result = MyExporter.Read(_tempFile);
        Assert.AreEqual("data", result);
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
            File.Delete(_tempFile);
    }

    public void Dispose()
    {
        // Fallback safety net
        Cleanup();
    }
}
```

**Key points:**

| Scenario | Solution |
|----------|----------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` |
| Flaky API | `[Retry(3)]` + `[Timeout]` |
| Guaranteed cleanup | `[TestCleanup]` (runs even on failure) |

`[TestCleanup]` always executes after each test regardless of pass/fail, making it the right place for temp file deletion. `IDisposable` is a secondary safety net.
